const body = $input.first().json.body || $input.first().json;
const place_id = body.place_id;
const website = body.website;
const business_name = body.business_name || 'Unknown';
if (!place_id) throw new Error('place_id is required');
if (!website) throw new Error('website is required (lead must have a website)');
let url = String(website).trim();
if (!/^https?:\/\//i.test(url)) url = 'https://' + url;
// Note: n8n task-runner sandbox does not expose the URL constructor, so we
// validate with a regex instead. Good enough for our use case.
if (!/^https?:\/\/[^\s]+\.[^\s]+/i.test(url)) {
  throw new Error('Invalid website URL: ' + website);
}
return [{ json: { place_id, business_name, website: url, started_at: new Date().toISOString() } }];

const homepageResp = $input.first();
const html = String(homepageResp.json.data || homepageResp.json.body || homepageResp.json || '');
const base = $('Validate Input').first().json.website;

// n8n task-runner sandbox doesn't expose the URL constructor, so we parse manually.
function getOrigin(u) {
  const m = String(u).match(/^(https?:\/\/[^\/]+)/i);
  return m ? m[1] : u;
}
function getPathFromAbs(u) {
  const m = String(u).match(/^https?:\/\/[^\/]+(\/[^?#]*)?/i);
  return (m && m[1]) || '/';
}
function absolutize(href, baseUrl) {
  if (!href) return null;
  href = String(href).trim();
  if (!href || href.startsWith('#') || href.startsWith('javascript:') || href.startsWith('mailto:') || href.startsWith('tel:')) return null;
  // Strip fragment
  href = href.split('#')[0];
  if (!href) return null;
  // Already absolute
  if (/^https?:\/\//i.test(href)) return href;
  // Protocol-relative
  if (href.startsWith('//')) {
    const proto = (baseUrl.match(/^(https?):/i) || [null, 'https'])[1];
    return proto + ':' + href;
  }
  const origin = getOrigin(baseUrl);
  // Root-relative
  if (href.startsWith('/')) return origin + href;
  // Path-relative — append to base directory
  const basePath = getPathFromAbs(baseUrl).replace(/\/[^\/]*$/, '/');
  return origin + basePath + href;
}
const origin = getOrigin(base);

function stripTags(s) {
  return s
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
    .replace(/<!--[\s\S]*?-->/g, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

const linkRe = /<a[^>]+href\s*=\s*["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi;
const rawLinks = [];
let m;
while ((m = linkRe.exec(html)) !== null) {
  rawLinks.push({ href: m[1], text: stripTags(m[2]).slice(0, 80) });
  if (rawLinks.length > 500) break;
}

const seen = new Set();
const internal = [];
for (const l of rawLinks) {
  const abs = absolutize(l.href, base);
  if (!abs) continue;
  const absOrigin = getOrigin(abs);
  if (absOrigin !== origin) continue;
  // Dedup by pathname without trailing slash
  const path = getPathFromAbs(abs).replace(/\/$/, '') || '/';
  if (path === '/' || path === '') continue; // skip homepage itself
  const key = origin + path;
  if (seen.has(key)) continue;
  seen.add(key);
  internal.push({ url: key, text: l.text || '(no text)' });
  if (internal.length > 80) break;
}

const homepageText = stripTags(html).slice(0, 6000);

return [{ json: { homepage_text: homepageText, homepage_url: base, links: internal, link_count: internal.length } }];

