const resp = $input.first().json;
const clean = $('Clean Homepage + Extract Links').first().json;
const availableUrls = new Set((clean.links || []).map(function(l){ return l.url; }));
let parsed = { rationale: '', selected_pages: [] };
try {
  const content = resp.choices && resp.choices[0] && resp.choices[0].message && resp.choices[0].message.content;
  if (content) parsed = JSON.parse(content);
} catch(e) { parsed = { rationale: 'LLM JSON parse failed: ' + e.message, selected_pages: [] }; }
const valid = (parsed.selected_pages || []).filter(function(p){ return p && p.url && availableUrls.has(p.url); }).slice(0, 5);
let selected = valid;
if (selected.length === 0) {
  const heuristicPaths = ['/contact', '/about', '/team', '/staff', '/leadership', '/our-team', '/meet-the-team', '/people', '/our-people'];
  const heuristicMatch = (clean.links || []).filter(function(l){
    const p = (l.url || '').toLowerCase();
    return heuristicPaths.some(function(h){ return p.endsWith(h) || p.indexOf(h + '/') >= 0; });
  }).slice(0, 5);
  selected = heuristicMatch.map(function(l, i){ return { url: l.url, reason: 'heuristic fallback', priority: i + 1 }; });
}
const rationale = (parsed.rationale || '') + (valid.length === 0 ? ' [LLM returned no valid URLs, used heuristic fallback]' : '');
if (selected.length === 0) {
  return [{ json: { _targetUrl: '__SKIP__', _isPlaceholder: true, rationale: rationale, selected_pages: [] } }];
}
return selected.map(function(p){ return { json: { _targetUrl: p.url, _reason: p.reason, _priority: p.priority, _rationale: rationale, _selected_pages: selected } }; });

function stripTags(s) {
  return String(s || '')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
    .replace(/<!--[\s\S]*?-->/g, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}
const pageItems = $input.all();
const selectionItems = $('Parse Page Selection').all();
const pages = [];
pageItems.forEach(function(item, idx){
  const selMeta = (selectionItems[idx] && selectionItems[idx].json) || {};
  if (selMeta._isPlaceholder) return;
  const j = item.json || {};
  const raw = String(j.data || j.body || j || '');
  if (!raw || raw.length < 50) {
    pages.push({ url: selMeta._targetUrl, status: 'empty', bytes: raw.length, text: '', reason: selMeta._reason });
    return;
  }
  const text = stripTags(raw).slice(0, 6000);
  pages.push({ url: selMeta._targetUrl, status: 'ok', bytes: raw.length, text: text, reason: selMeta._reason });
});
const homepageData = $('Clean Homepage + Extract Links').first().json;
const firstSel = (selectionItems[0] && selectionItems[0].json) || {};
return [{ json: { homepage_url: homepageData.homepage_url, homepage_text: homepageData.homepage_text, pages: pages, page_count: pages.filter(function(p){ return p.status === 'ok'; }).length, rationale: firstSel._rationale || '', selected_pages: firstSel._selected_pages || [] } }];

