const llmResp = $input.first().json;
const cleaned = $('Clean Selected Pages').first().json;
const startRow = $('Start Deep Enrich Run').first().json;
const runRow = Array.isArray(startRow) ? startRow[0] : startRow;
const runId = runRow && runRow.id;
const startedAt = $('Validate Input').first().json.started_at;
let parsed = null;
let modelUsed = 'failed';
let tokensIn = null;
let tokensOut = null;
try {
  if (llmResp.choices && llmResp.choices[0] && llmResp.choices[0].message) {
    parsed = JSON.parse(llmResp.choices[0].message.content);
    modelUsed = 'groq-llama3.3-70b';
  }
  if (llmResp.usage) {
    tokensIn = llmResp.usage.prompt_tokens || null;
    tokensOut = llmResp.usage.completion_tokens || null;
  }
} catch(e) {}
if (!parsed) {
  parsed = { personal_contacts: [], generic_contacts: { emails: [], phones: [], address: '' }, social_profiles: {}, confidence: 0, notes: 'LLM extraction failed' };
}
const personal = (parsed.personal_contacts || []).filter(function(c){ return c && (c.name || c.email || c.phone); });
const generic = parsed.generic_contacts || { emails: [], phones: [], address: '' };
generic.emails = Array.isArray(generic.emails) ? generic.emails.filter(Boolean) : [];
generic.phones = Array.isArray(generic.phones) ? generic.phones.filter(Boolean) : [];
generic.address = String(generic.address || '');
const socials = parsed.social_profiles || {};
const hasPersonalEmail = personal.some(function(c){ return c.email && c.email.length > 0; });
const hasPersonalPhone = personal.some(function(c){ return c.phone && c.phone.length > 0; });
const hasOwnerName = personal.some(function(c){ return c.name && c.name.length > 0; });
const personalCount = personal.length;
const now = new Date();
const durationMs = startedAt ? (now.getTime() - new Date(startedAt).getTime()) : null;
const pagesVisited = (cleaned.pages || []).map(function(p){ return { url: p.url, status: p.status, bytes: p.bytes, reason: p.reason }; });
pagesVisited.unshift({ url: cleaned.homepage_url, status: 'ok', bytes: (cleaned.homepage_text || '').length, reason: 'homepage' });
return [{ json: { _runId: runId, pages_visited: pagesVisited, page_selection_rationale: cleaned.rationale || '', personal_contacts: personal, generic_contacts: generic, social_profiles: socials, confidence: Math.min(1, Math.max(0, Number(parsed.confidence) || 0)), llm_notes: String(parsed.notes || '').slice(0, 2000), has_personal_email: hasPersonalEmail, has_personal_phone: hasPersonalPhone, has_owner_name: hasOwnerName, personal_contact_count: personalCount, model_used: modelUsed, tokens_input: tokensIn, tokens_output: tokensOut, status: modelUsed === 'failed' ? 'failed' : 'completed', error_message: modelUsed === 'failed' ? 'LLM extraction failed (see Groq response)' : null, completed_at: now.toISOString(), duration_ms: durationMs } }];

const parsed = $('Parse Extraction').first().json;
const place_id = $('Validate Input').first().json.place_id;
return [{ json: { success: parsed.status === 'completed', place_id: place_id, deep_enrich_id: parsed._runId, status: parsed.status, summary: { personal_contact_count: parsed.personal_contact_count, has_personal_email: parsed.has_personal_email, has_personal_phone: parsed.has_personal_phone, has_owner_name: parsed.has_owner_name, confidence: parsed.confidence, pages_crawled: (parsed.pages_visited || []).filter(function(p){ return p.status === 'ok'; }).length, duration_ms: parsed.duration_ms, model_used: parsed.model_used }, personal_contacts: parsed.personal_contacts, generic_contacts: parsed.generic_contacts, social_profiles: parsed.social_profiles, llm_notes: parsed.llm_notes, rationale: parsed.page_selection_rationale, error: parsed.error_message } }];
